mapper.select:
SELECT DISTINCT sd.${field} as entityUniqueId,
                sgpd.gene_panel_id as genePanelId, sgpd.genetic_profile_id as geneticProfileId
FROM  sgpd
         JOIN  sd ON sgpd.sample_unique_id=sd.sample_unique_id
WHERE sd.${field} IN
      (
          ${sampleStableIdsJoined}
          )
  AND sgpd.genetic_profile_id IN
      (
          ${profileIdsJoined}
          )
